arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    // EF9: Migrate() now manages its own transaction internally.
    // Wrapping it in a user transaction throws InvalidOperationException.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

